string reverseParentheses(string s) {
    stack<char> sStack;
    string result = "";
    for (char c : s) {
        if (c == '(' || c == '[' || c == '{') {
            sStack.push(c);
        } else if (sStack.empty() || sStack.top() != c) {
            result += c;
            sStack.pop();
        }
    }
    while (!sStack.empty()) {
        result += sStack.top();
        sStack.pop();
    }
    return result;
}
```

